def count_ways(n):
    if n == 0:
        return 1  # There's one way to stay on the ground (do nothing)
    elif n < 0:
        return 0  # No way to climb negative stairs

    # Create a list to store the number of ways to reach each stair
    dp = [0] * (n + 1)
    dp[0] = 1  # One way to stay on the ground (do nothing)

    # Fill the dp array
    for i in range(1, n + 1):
        dp[i] += dp[i - 1]  # 1 step
        if i > 1:
            dp[i] += dp[i - 2]  # 2 steps
        if i > 2:
            dp[i] += dp[i - 3]  # 3 steps

    return dp[n]

